msg.metadataKeys = JSON.stringify(Object.keys(metadata)); // register current metadata keys
/* remove current msg keys */
delete msg.method;
delete msg.params;

return {msg: msg, metadata: metadata, msgType: msgType};

/**
 * Function to calculate the average of an array
 * @param array array to calculate the average
 * @return decimal result of the average
 */
function calculateAverage(array){
    var sum = 0; // declare sum

    for(var i=0;i<array.length;i++)
        sum += array[i].value;

    return sum/array.length;
}

/* get the old keys and the current keys of metadata */
var oldKeys = JSON.parse(msg.metadataKeys);
delete msg.metadataKeys;
var currentKeys = Object.keys(metadata);

/* check if it's a timeseries key
and calculate the average of the values in the array */
for(const singleKey of currentKeys){
    if(!oldKeys.includes(singleKey)){ // if the key it's not included it means it's a telemetry one
        msg["average_"+singleKey]=calculateAverage(JSON.parse(metadata[singleKey])); // calculate and save the average
        delete metadata[singleKey]; // delete the metadata key
    }
}

return {msg: msg, metadata: metadata, msgType: msgType};

